import React, { useState, useEffect } from 'react';
import { GraduationCap, Search, User, LogOut, Menu, X, Clock, Users, Star, Play, Bookmark, Filter, Grid, List, TrendingUp, Award, Heart, Share2 } from 'lucide-react';
import ProgressBar from './components/ProgressBar.jsx';
import AnimatedCounter from './components/AnimatedCounter.jsx';
import SearchBar from './components/SearchBar.jsx';

const Course = ({ courses }) => {
  // Auto-convert Dropbox URLs
  const processedCourses = courses.map(course => ({
    ...course,
    videoUrl: course.videoUrl?.includes('dropbox.com') && course.videoUrl?.includes('dl=0') 
      ? course.videoUrl.replace('dl=0', 'raw=1')
      : course.videoUrl
  }));

  const [filteredCourses, setFilteredCourses] = useState(processedCourses);

  // Convert Dropbox URL to direct video link
  const convertDropboxUrl = (url) => {
    if (url.includes('dropbox.com') && url.includes('dl=0')) {
      return url.replace('dl=0', 'raw=1');
    }
    return url;
  };
  const [activeFilter, setActiveFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('rating');
  const [showMobileMenu, setShowMobileMenu] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [username] = useState('Instructor');
  const [viewMode, setViewMode] = useState('grid');
  const [favorites, setFavorites] = useState(new Set());
  const [showAdvancedFilters, setShowAdvancedFilters] = useState(false);
  const [priceRange, setPriceRange] = useState([0, 200]);
  const [ratingFilter, setRatingFilter] = useState(0);

  const getVideoUrl = (url) => {
    if (!url) return null;
    if (url.includes('dropbox.com')) {
      return url.replace('dl=0', 'dl=1').replace('&amp;', '&');
    }
    if (url.includes('youtube.com/watch?v=')) {
      return url.replace('watch?v=', 'embed/');
    }
    return url;
  };

  useEffect(() => {
    let filtered = courses.filter(course => {
      const matchesFilter = activeFilter === 'all' || course.cat === activeFilter;
      const matchesSearch = course.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           course.instructor.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesFilter && matchesSearch;
    });

    filtered.sort((a, b) => {
      if (sortBy === 'price') return a.price - b.price;
      if (sortBy === 'enrolled') return b.enrolled - a.enrolled;
      return parseFloat(b.rating) - parseFloat(a.rating);
    });

    setFilteredCourses(filtered);
  }, [courses, activeFilter, searchTerm, sortBy]);

  const toggleFavorite = (courseId) => {
    setFavorites(prev => {
      const newFavorites = new Set(prev);
      if (newFavorites.has(courseId)) {
        newFavorites.delete(courseId);
      } else {
        newFavorites.add(courseId);
      }
      return newFavorites;
    });
  };

  const CourseCard = ({ course }) => (
    <div className={`bg-white rounded-xl overflow-hidden shadow-sm border border-gray-200 hover:transform hover:-translate-y-2 hover:shadow-2xl transition-all duration-500 group ${
      viewMode === 'list' ? 'flex' : ''
    }`}>
      <div className={`relative overflow-hidden ${
        viewMode === 'list' ? 'w-48 h-32' : 'h-40 sm:h-48'
      }`}>
        <img src={course.img} alt={course.title} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>

        {course.progress > 0 && (
          <div className="absolute top-3 left-3 bg-gradient-to-r from-green-500 to-green-600 text-white px-3 py-1 rounded-full text-xs font-semibold shadow-lg">
            {course.progress}% Complete
          </div>
        )}

        <div className="absolute top-3 right-3 flex space-x-2">
          <div className="bg-black/70 backdrop-blur-sm text-white px-2 py-1 rounded-full text-xs flex items-center">
            <Star className="w-3 h-3 mr-1 fill-yellow-400 text-yellow-400" />{course.rating}
          </div>
          <button
            onClick={(e) => {
              e.stopPropagation();
              toggleFavorite(course.id);
            }}
            className={`p-2 rounded-full backdrop-blur-sm transition-all duration-200 ${
              favorites.has(course.id) 
                ? 'bg-red-500 text-white' 
                : 'bg-white/20 text-white hover:bg-white/30'
            }`}
          >
            <Heart className={`w-4 h-4 ${favorites.has(course.id) ? 'fill-current' : ''}`} />
          </button>
        </div>

        <div className="absolute bottom-3 left-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <div className="flex space-x-2">
            <button className="flex-1 bg-white/90 backdrop-blur-sm text-gray-900 px-3 py-2 rounded-lg text-xs font-medium hover:bg-white transition-colors">
              <Play className="w-3 h-3 inline mr-1" />Preview
            </button>
            <button className="bg-white/20 backdrop-blur-sm text-white p-2 rounded-lg hover:bg-white/30 transition-colors">
              <Share2 className="w-3 h-3" />
            </button>
          </div>
        </div>
      </div>

      <div className={`p-4 sm:p-6 ${viewMode === 'list' ? 'flex-1' : ''}`}>
        <div className="flex items-start justify-between mb-2">
          <h3 className="text-base sm:text-lg font-bold text-gray-900 group-hover:text-blue-600 transition-colors">
            {course.title}
          </h3>
          {course.enrolled > 1000 && (
            <div className="bg-orange-100 text-orange-600 px-2 py-1 rounded-full text-xs font-semibold flex items-center">
              <TrendingUp className="w-3 h-3 mr-1" />Popular
            </div>
          )}
        </div>

        <p className="text-gray-600 text-sm mb-4 line-clamp-2">{course.desc}</p>

        <div className="flex items-center justify-between mb-4 text-xs text-gray-500 flex-wrap gap-2">
          <div className="flex items-center space-x-3">
            <span className={`px-3 py-1 rounded-full font-medium ${
              course.level === 'Beginner' ? 'bg-green-100 text-green-700' :
              course.level === 'Intermediate' ? 'bg-yellow-100 text-yellow-700' :
              'bg-red-100 text-red-700'
            }`}>
              {course.level}
            </span>
            <span className="flex items-center">
              <Clock className="w-3 h-3 mr-1" />{course.time}
            </span>
            <span className="flex items-center">
              <Users className="w-3 h-3 mr-1" />{course.enrolled.toLocaleString()}
            </span>
          </div>
        </div>

        {course.progress > 0 && (
          <div className="mb-4">
            <ProgressBar progress={course.progress} size="small" />
          </div>
        )}

        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3">
          <div>
            <div className="text-sm text-gray-600 mb-1">{course.instructor}</div>
            <div className="text-xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
              ₹{course.price.toLocaleString()}
            </div>
          </div>
          <button 
            onClick={() => setSelectedCourse(course)}
            className="w-full sm:w-auto bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white px-6 py-3 rounded-xl text-sm font-semibold transition-all duration-200 transform hover:scale-105 shadow-lg hover:shadow-xl"
          >
            Enroll Now
          </button>
        </div>
      </div>
    </div>
  );

  const Modal = ({ course, onClose }) => (
    <div className="fixed inset-0 flex items-center justify-center bg-black/50 z-50 p-4">
      <div className="bg-white rounded-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
        <div className="relative">
          <img className="w-full h-48 sm:h-64 object-cover" src={course.img} alt={course.title} />
          <button onClick={onClose} className="absolute top-4 right-4 bg-white/90 text-gray-700 w-8 h-8 rounded-full flex items-center justify-center hover:bg-white transition">
            <X className="w-4 h-4" />
          </button>
        </div>
        <div className="p-6 sm:p-8">
          <div className="flex flex-col sm:flex-row justify-between items-start mb-4 gap-2">
            <h2 className="text-xl sm:text-2xl font-bold text-gray-900">{course.title}</h2>
            <span className="text-xl sm:text-2xl font-bold text-blue-600">₹{course.price.toLocaleString()}</span>
          </div>
          <p className="text-gray-600 mb-6">{course.desc}</p>

          {course.videoUrl && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold mb-3">Course Preview</h3>
              {course.videoUrl.includes('youtube.com') || course.videoUrl.includes('youtu.be') ? (
                <iframe 
                  className="w-full h-64 rounded-lg"
                  src={course.videoUrl.replace('watch?v=', 'embed/')}
                  frameBorder="0"
                  allowFullScreen
                />
              ) : (
                <video 
                  className="w-full h-64 rounded-lg bg-black"
                  controls
                  preload="metadata"
                >
                  <source src={course.videoUrl.replace(/dl=0/g, 'raw=1').replace(/&amp;/g, '&')} type="video/mp4" />
                  Your browser does not support the video tag.
                </video>
              )}
            </div>
          )}

          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Instructor</div>
              <div className="font-semibold text-gray-900">{course.instructor}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Duration</div>
              <div className="font-semibold text-gray-900">{course.time}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Level</div>
              <div className="font-semibold text-gray-900">{course.level}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Students</div>
              <div className="font-semibold text-gray-900">{course.enrolled.toLocaleString()}</div>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row space-y-2 sm:space-y-0 sm:space-x-4">
            <button className="flex-1 bg-green-600 hover:bg-green-700 text-white font-semibold py-3 px-6 rounded-lg transition">
              <Play className="w-4 h-4 inline mr-2" />Preview as Instructor
            </button>
            <button className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-6 py-3 rounded-lg transition">
              <Bookmark className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50" style={{fontFamily: 'Inter, sans-serif'}}>
      <nav className="bg-white shadow-sm fixed w-full z-40 border-b border-gray-200 top-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <a href="#" className="text-blue-600 font-bold text-xl sm:text-2xl flex items-center">
              <GraduationCap className="w-6 h-6 sm:w-8 sm:h-8 mr-2" />RiseGen
            </a>

            <button onClick={() => setShowMobileMenu(!showMobileMenu)} className="md:hidden p-2 rounded-lg text-gray-600 hover:bg-gray-100">
              <Menu className="w-6 h-6" />
            </button>

            <div className="hidden md:flex items-center space-x-4">
              <SearchBar 
                onSearch={setSearchTerm}
                placeholder="Search courses..."
                suggestions={courses.map(course => course.title)}
              />
              <div className="flex items-center space-x-2 text-gray-700">
                <User className="w-4 h-4" />
                <span className="text-sm font-medium">{username}</span>
              </div>
              <button className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2 rounded-lg text-sm transition">
                <LogOut className="w-4 h-4 inline mr-1" />Logout
              </button>
            </div>
          </div>
        </div>
      </nav>

      <section className="pt-32 pb-16 bg-gradient-to-br from-blue-50 via-white to-purple-50 relative overflow-hidden">
        <div className="absolute inset-0 bg-grid-pattern opacity-5"></div>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center relative">
          <div className="mb-8">
            <div className="inline-flex items-center bg-blue-100 text-blue-700 px-4 py-2 rounded-full text-sm font-medium mb-4">
              <Award className="w-4 h-4 mr-2" />
              #1 Learning Platform
            </div>
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold mb-6 text-gray-900">
              Learn Without <span className="bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">Limits</span>
            </h1>
            <p className="text-lg sm:text-xl mb-8 text-gray-600 max-w-3xl mx-auto leading-relaxed">
              Start, switch, or advance your career with {courses.length} courses, Professional Certificates, and degrees from world-class universities and companies.
            </p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-8 max-w-4xl mx-auto mb-12">
            <div className="bg-white/80 backdrop-blur-sm rounded-2xl p-6 shadow-lg border border-white/20">
              <div className="text-blue-600 mb-2">
                <AnimatedCounter end={courses.length} />
              </div>
              <div className="text-sm font-medium text-gray-600">Expert Courses</div>
            </div>
            <div className="bg-white/80 backdrop-blur-sm rounded-2xl p-6 shadow-lg border border-white/20">
              <div className="text-purple-600 mb-2">
                <AnimatedCounter end={50000} suffix="+" />
              </div>
              <div className="text-sm font-medium text-gray-600">Happy Students</div>
            </div>
            <div className="bg-white/80 backdrop-blur-sm rounded-2xl p-6 shadow-lg border border-white/20">
              <div className="text-green-600 mb-2">
                <AnimatedCounter end={100} suffix="%" />
              </div>
              <div className="text-sm font-medium text-gray-600">Online Learning</div>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-4 rounded-xl font-semibold text-lg hover:from-blue-700 hover:to-purple-700 transition-all duration-200 transform hover:scale-105 shadow-lg">
              Start Learning Today
            </button>
            <button className="border-2 border-gray-300 text-gray-700 px-8 py-4 rounded-xl font-semibold text-lg hover:border-blue-600 hover:text-blue-600 transition-all duration-200">
              Watch Demo
            </button>
          </div>
        </div>
      </section>

      <div className="bg-white border-b border-gray-200 py-6">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
            <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 w-full lg:w-auto">
              <div className="flex flex-wrap gap-2">
                {['all', 'development', 'ai', 'design', 'business'].map(filter => (
                  <button 
                    key={filter}
                    onClick={() => setActiveFilter(filter)}
                    className={`px-4 py-2 rounded-xl text-sm font-medium transition-all duration-200 ${
                      activeFilter === filter 
                        ? 'bg-gradient-to-r from-blue-600 to-purple-600 text-white shadow-lg transform scale-105' 
                        : 'text-gray-700 bg-gray-100 hover:bg-gray-200 hover:scale-105'
                    }`}
                  >
                    {filter === 'all' ? 'All Courses' : filter === 'ai' ? 'AI & ML' : filter.charAt(0).toUpperCase() + filter.slice(1)}
                  </button>
                ))}
              </div>

              <button
                onClick={() => setShowAdvancedFilters(!showAdvancedFilters)}
                className="flex items-center px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-xl hover:bg-gray-200 transition-colors"
              >
                <Filter className="w-4 h-4 mr-2" />
                Advanced Filters
              </button>
            </div>

            <div className="flex items-center gap-4 w-full lg:w-auto">
              <div className="flex items-center bg-gray-100 rounded-xl p-1">
                <button
                  onClick={() => setViewMode('grid')}
                  className={`p-2 rounded-lg transition-colors ${
                    viewMode === 'grid' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-600'
                  }`}
                >
                  <Grid className="w-4 h-4" />
                </button>
                <button
                  onClick={() => setViewMode('list')}
                  className={`p-2 rounded-lg transition-colors ${
                    viewMode === 'list' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-600'
                  }`}
                >
                  <List className="w-4 h-4" />
                </button>
              </div>

              <select 
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="bg-white border border-gray-300 rounded-xl px-4 py-2 text-gray-700 focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm min-w-[160px]"
              >
                <option value="rating">⭐ Highest Rated</option>
                <option value="price">💰 Price: Low to High</option>
                <option value="enrolled">🔥 Most Popular</option>
              </select>
            </div>
          </div>

          {showAdvancedFilters && (
            <div className="mt-6 p-6 bg-gray-50 rounded-2xl border border-gray-200">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Price Range</label>
                  <div className="flex items-center space-x-4">
                    <input
                      type="range"
                      min="0"
                      max="200"
                      value={priceRange[1]}
                      onChange={(e) => setPriceRange([0, parseInt(e.target.value)])}
                      className="flex-1"
                    />
                    <span className="text-sm font-medium text-gray-600">₹0 - ₹{priceRange[1]}</span>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Minimum Rating</label>
                  <select
                    value={ratingFilter}
                    onChange={(e) => setRatingFilter(parseFloat(e.target.value))}
                    className="w-full bg-white border border-gray-300 rounded-lg px-3 py-2 text-sm"
                  >
                    <option value={0}>Any Rating</option>
                    <option value={4.5}>4.5+ Stars</option>
                    <option value={4.0}>4.0+ Stars</option>
                    <option value={3.5}>3.5+ Stars</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Quick Filters</label>
                  <div className="flex flex-wrap gap-2">
                    <button className="px-3 py-1 text-xs bg-white border border-gray-300 rounded-full hover:bg-gray-50">
                      Free Courses
                    </button>
                    <button className="px-3 py-1 text-xs bg-white border border-gray-300 rounded-full hover:bg-gray-50">
                      With Certificate
                    </button>
                    <button className="px-3 py-1 text-xs bg-white border border-gray-300 rounded-full hover:bg-gray-50">
                      Beginner Friendly
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 sm:py-12">
        <div className={`${viewMode === 'grid' 
          ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6' 
          : 'space-y-6'
        }`}>
          {filteredCourses.map(course => (
            <CourseCard key={course.id} course={course} />
          ))}
        </div>

        {filteredCourses.length === 0 && (
          <div className="text-center py-16">
            <div className="w-24 h-24 mx-auto mb-6 bg-gray-100 rounded-full flex items-center justify-center">
              <Search className="w-12 h-12 text-gray-400" />
            </div>
            <h3 className="text-xl font-semibold text-gray-900 mb-2">No courses found</h3>
            <p className="text-gray-600 mb-6">Try adjusting your search criteria or filters</p>
            <button 
              onClick={() => {
                setActiveFilter('all');
                setSearchTerm('');
                setShowAdvancedFilters(false);
                setPriceRange([0, 200]);
                setRatingFilter(0);
              }}
              className="bg-blue-600 text-white px-6 py-3 rounded-xl font-medium hover:bg-blue-700 transition-colors"
            >
              Clear All Filters
            </button>
          </div>
        )}
      </div>

      {selectedCourse && (
        <Modal course={selectedCourse} onClose={() => setSelectedCourse(null)} />
      )}
    </div>
  );
};

export default Course;
